1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	interface QuoteStep {
7	  op: "quote";
8	  items: Item[];
9	}
10	
11	interface Scenario {
12	  customer: { yearsWithMHPCO: number };
13	  steps: QuoteStep[];
14	}
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	const COMPONENT_PREMIUM = 25;
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	const FIRST_INSURANCE_SURCHARGE = 1.1;
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const PROCESSING_FEE = 5;
31	
32	// Base premium of a single item (main item or one component).
33	const itemBase = (item: Item): number =>
34	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
35	
36	// Curse adds 50% of the affected item's base premium.
37	const curseSurcharge = (items: Item[]): number =>
38	  sum(items.filter((item) => item.cursed).map((item) => CURSE_SURCHARGE_RATE * itemBase(item)));
39	
40	// Base premium for `count` alike components: a group of exactly 3 forms a
41	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
42	// COMPONENT_PREMIUM.
43	const componentGroupPremium = (count: number): number =>
44	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
45	
46	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
47	
48	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
49	
50	// Count how many alike components of each type appear (e.g. { rune: 2 }).
51	const countByType = (items: Item[]): Map<string, number> =>
52	  items.reduce((counts, item) => {
53	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
54	    return counts;
55	  }, new Map<string, number>());
56	
57	const mainItemsPremium = (items: Item[]): number =>
58	  sum(items.filter((item) => !isComponent(item)).map((item) => BASE_PREMIUM[item.type] ?? 0));
59	
60	const componentsPremium = (items: Item[]): number =>
61	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
62	
63	const basePremium = (items: Item[]): number =>
64	  mainItemsPremium(items) + componentsPremium(items);
65	
66	// Round up to a whole number in MHPCO's favour, guarding against
67	// floating-point noise (e.g. 197.5000000001) before the ceiling by snapping
68	// to 6 decimal places first.
69	const FLOAT_GUARD_PRECISION = 1e6;
70	const roundUpToWhole = (value: number): number =>
71	  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);
72	
73	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
74	  const results = scenario.steps.map((step) => {
75	    const base = basePremium(step.items);
76	    const premium =
77	      base * FIRST_INSURANCE_SURCHARGE + curseSurcharge(step.items) + PROCESSING_FEE;
78	    return { premium: roundUpToWhole(premium) };
79	  });
80	  return { results };
81	};
